query:
UPDATE scenarios SET descriptionEn = 'Execute a complete PO→GR→SO→GI→Cycle Count cycle without errors. Objective: master the standard logistics flow.' WHERE name = 'Scénario 1 — Cycle propre';
UPDATE scenarios SET descriptionEn = 'A GR was created but not posted. Detect the anomaly, post the transaction, and continue the cycle.' WHERE name = 'Scénario 2 — Réception fantôme (GR non postée)';
UPDATE scenarios SET descriptionEn = 'A SO was created for a quantity exceeding available stock. Manage the backorder and replenish inventory.' WHERE name = 'Scénario 3 — Stock insuffisant';
UPDATE scenarios SET descriptionEn = 'Physical count reveals a discrepancy against system stock. Resolve it with an ADJ transaction.' WHERE name = 'Scénario 4 — Écart d\'inventaire';
UPDATE scenarios SET descriptionEn = 'Multiple simultaneous anomalies: unposted GR, potential negative stock, inventory discrepancy. Resolve them in the correct order.' WHERE name = 'Scénario 5 — Non-conformités multiples';
UPDATE scenarios SET descriptionEn = 'Receive goods and store them in the correct bin according to capacity and zone rules. Objective: master the LT01 putaway process.' WHERE name LIKE '%Rangement structuré%';
UPDATE scenarios SET descriptionEn = 'Attempt to store a quantity exceeding a bin capacity. The system must detect the overflow and suggest an alternative location.' WHERE name LIKE '%Validation de la capacité%';
UPDATE scenarios SET descriptionEn = 'Three lots of the same SKU are in stock. Follow FIFO order during putaway and order picking.' WHERE name LIKE '%FIFO%';
UPDATE scenarios SET descriptionEn = 'Perform a cycle count and analyze discrepancies between system stock and physical stock.' WHERE name LIKE '%Inventaire cyclique simple%';
UPDATE scenarios SET descriptionEn = 'Identify a significant discrepancy, provide a justification, and perform the adjustment in compliance with internal rules.' WHERE name LIKE '%Analyse d''écart%';
UPDATE scenarios SET descriptionEn = 'Analyze inventory levels and generate a replenishment recommendation aligned with the defined Min/Max and safety stock parameters.' WHERE name LIKE '%Réapprovisionnement%';
UPDATE scenarios SET descriptionEn = 'Calculate and interpret the inventory turnover rate to identify overstock or underperformance situations.' WHERE name LIKE '%rotation des stocks%';
UPDATE scenarios SET descriptionEn = 'Identify the root causes of a low service level and analyze the impact of logistics errors on overall performance.' WHERE name LIKE '%taux de service%';
UPDATE scenarios SET descriptionEn = 'Analyze multiple combined KPIs and propose a strategic decision based on the observed data.' WHERE name LIKE '%Diagnostic global%';
UPDATE scenarios SET descriptionEn = 'Complete a full supplier to warehouse to customer cycle following all operational rules.' WHERE name LIKE '%Cycle opérationnel complet%';
UPDATE scenarios SET descriptionEn = 'Manage a situation involving inventory discrepancies and propose corrective actions.' WHERE name LIKE '%Gestion d''écarts%';
UPDATE scenarios SET descriptionEn = 'Analyze global performance indicators and formulate a justified strategic decision.' WHERE name LIKE '%Analyse décisionnelle%';

